import React, { useState } from "react";
import { ethers } from "ethers";
import Web3Modal from "web3modal";
import { CONTRACT_ADDRESS, CONTRACT_ABI } from "../../constants";

export default function UserDashboard() {
  const [address, setAddress] = useState("");
  const [info, setInfo] = useState(null);
  const [serviceMsg, setServiceMsg] = useState("");

  const loadStatus = async () => {
    try {
      const web3Modal = new Web3Modal();
      const conn = await web3Modal.connect();
      const provider = new ethers.providers.Web3Provider(conn);
      const signer = provider.getSigner();
      const addr = await signer.getAddress();
      setAddress(addr);

      const contract = new ethers.Contract(CONTRACT_ADDRESS, CONTRACT_ABI, provider);
      const kycInfo = await contract.getKycInfo(addr);
      setInfo({
        verified: kycInfo.verified,
        level: kycInfo.level,
        verifiedAt: kycInfo.verifiedAt.toNumber(),
        expiresAt: kycInfo.expiresAt.toNumber()
      });
    } catch (err) {
      console.error(err);
    }
  };

  const accessService = () => {
    if (!info || !info.verified || info.expiresAt * 1000 < Date.now()) {
      setServiceMsg("❌ Access denied. You need valid KYC.");
    } else {
      setServiceMsg("✅ Access granted to KYC-gated demo service.");
    }
  };

  return (
    <div className="card">
      <h2>User Dashboard</h2>
      <p className="muted">
        Connect your wallet to see if you have a reusable KYC credential.
      </p>
      <button onClick={loadStatus}>Connect Wallet & Load Status</button>
      {address && (
        <p>
          Connected as <code>{address}</code>
        </p>
      )}
      {info && (
        <>
          <p>
            Status:{" "}
            {info.verified ? (
              <span className="badge badge-ok">KYC Verified</span>
            ) : (
              <span className="badge badge-bad">Not Verified</span>
            )}
          </p>
          <p>Level: {info.level}</p>
          <p>
            Verified at:{" "}
            {info.verifiedAt
              ? new Date(info.verifiedAt * 1000).toLocaleString()
              : "n/a"}
          </p>
          <p>
            Expires at:{" "}
            {info.expiresAt
              ? new Date(info.expiresAt * 1000).toLocaleString()
              : "n/a"}
          </p>
        </>
      )}
      <hr />
      <h3>Sample KYC‑Gated Service</h3>
      <button onClick={accessService}>Use Service</button>
      {serviceMsg && <p>{serviceMsg}</p>}
    </div>
  );
}
